import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

// Helper function to get weather emoji based on condition
const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
  return '🌤️'; // Default partly cloudy
};

export default function GeneratedComponent({
  city = 'New York',
  temperature = 72,
  condition = 'Sunny',
  humidity = 60,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 70, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☀️', high: 73, low: 60 },
    { day: 'Fri', icon: '☀️', high: 78, low: 64 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      border={true}
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <Text
          variant="h2"
          color="var(--ggui-color-primary-900, #0c4a6e)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16}>
          <Row align="center" gap={16}>
            {/* Temperature */}
            <div style={{ flex: 1 }}>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  lineHeight: 1,
                }}
              >
                {temperature}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="medium"
                style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
              >
                {unit}
              </Text>
            </div>

            {/* Weather Icon and Condition */}
            <Stack direction="vertical" gap={8} align="center">
              <div
                style={{
                  fontSize: '64px',
                  lineHeight: 1,
                }}
              >
                {weatherEmoji}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="medium"
                align="center"
              >
                {condition}
              </Text>
            </Stack>
          </Row>

          {/* Weather Details Grid */}
          <Row gap={16} justify="between" style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
            {/* Humidity */}
            <Box
              padding="var(--ggui-spacing-4, 16px)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                background: 'rgba(255, 255, 255, 0.5)',
                flex: 1,
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                Humidity
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="semibold"
                style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
              >
                {humidity}%
              </Text>
            </Box>

            {/* Wind Speed */}
            <Box
              padding="var(--ggui-spacing-4, 16px)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                background: 'rgba(255, 255, 255, 0.5)',
                flex: 1,
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-neutral-500, #6b7280)"
                weight="medium"
              >
                Wind Speed
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="semibold"
                style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
              >
                {windSpeed} mph
              </Text>
            </Box>
          </Row>
        </Stack>

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} justify="between" wrap={true}>
            {forecast.map((day, idx) => (
              <Box
                key={idx}
                padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  background: 'rgba(255, 255, 255, 0.6)',
                  textAlign: 'center',
                  flex: '1 1 18%',
                  minWidth: '70px',
                }}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-700, #0369a1)"
                  weight="semibold"
                >
                  {day.day}
                </Text>
                <div
                  style={{
                    fontSize: '28px',
                    lineHeight: 1,
                    margin: 'var(--ggui-spacing-1, 4px) 0',
                  }}
                >
                  {day.icon}
                </div>
                <div
                  style={{
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-primary-600, #0284c7)',
                    fontWeight: 'var(--ggui-font-weight-medium, 500)',
                    marginTop: 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  <div>{day.high}°</div>
                  <div style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                    {day.low}°
                  </div>
                </div>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast?: ForecastDay[];
}

const getWeatherIcon = (condition: string): string => {
  const conditionLower = condition.toLowerCase();

  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) {
    return '☀️';
  } else if (conditionLower.includes('cloud')) {
    return '☁️';
  } else if (conditionLower.includes('rain')) {
    return '🌧️';
  } else if (conditionLower.includes('snow')) {
    return '❄️';
  } else if (conditionLower.includes('wind')) {
    return '💨';
  } else if (conditionLower.includes('storm') || conditionLower.includes('thunder')) {
    return '⛈️';
  } else if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return '🌫️';
  }
  return '🌡️';
};

const ForecastItem: React.FC<{ day: ForecastDay }> = ({ day }) => (
  <Stack
    direction="column"
    align="center"
    justify="center"
    style={{
      padding: 'var(--ggui-spacing-sm, 8px)',
      borderRadius: 'var(--ggui-border-radius-md, 8px)',
      backgroundColor: 'var(--ggui-color-surface-variant, #f5f5f5)',
      minWidth: '80px',
      textAlign: 'center',
    }}
  >
    <Text variant="caption" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
      {day.day}
    </Text>
    <Text style={{ fontSize: '20px', margin: 'var(--ggui-spacing-xs, 4px) 0' }}>
      {getWeatherIcon(day.condition)}
    </Text>
    <Stack direction="row" gap="var(--ggui-spacing-xs, 4px)">
      <Text variant="caption" style={{ fontWeight: 'bold' }}>
        {day.high}°
      </Text>
      <Text variant="caption" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
        {day.low}°
      </Text>
    </Stack>
  </Stack>
);

export default function GeneratedComponent(props: Props): JSX.Element {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast = [],
  } = props;

  const mainIcon = getWeatherIcon(condition);

  return (
    <Card style={{ padding: 'var(--ggui-spacing-lg, 16px)' }}>
      <Stack direction="column" gap="var(--ggui-spacing-md, 12px)">
        {/* Header with City Name */}
        <Stack direction="row" justify="space-between" align="center">
          <Text variant="headline" style={{ color: 'var(--ggui-color-on-surface, #000)' }}>
            {city}
          </Text>
        </Stack>

        {/* Main Temperature Section */}
        <Stack
          direction="column"
          align="center"
          gap="var(--ggui-spacing-sm, 8px)"
          style={{
            padding: 'var(--ggui-spacing-lg, 16px) 0',
            backgroundColor: 'var(--ggui-color-surface-dim, #fafafa)',
            borderRadius: 'var(--ggui-border-radius-lg, 12px)',
          }}
        >
          <Text style={{ fontSize: '56px' }}>{mainIcon}</Text>
          <Stack direction="row" align="baseline" gap="var(--ggui-spacing-xs, 4px)">
            <Text
              style={{
                fontSize: '48px',
                fontWeight: 'bold',
                color: 'var(--ggui-color-primary, #1976d2)',
              }}
            >
              {temperature}
            </Text>
            <Text style={{ fontSize: '24px', color: 'var(--ggui-color-on-surface, #000)' }}>
              °{unit}
            </Text>
          </Stack>
          <Text variant="body" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
            {condition}
          </Text>
        </Stack>

        {/* Current Conditions Stats */}
        <Stack
          direction="row"
          gap="var(--ggui-spacing-md, 12px)"
          justify="space-around"
          style={{
            backgroundColor: 'var(--ggui-color-surface-variant, #f5f5f5)',
            padding: 'var(--ggui-spacing-md, 12px)',
            borderRadius: 'var(--ggui-border-radius-md, 8px)',
          }}
        >
          <Stack direction="column" align="center" gap="var(--ggui-spacing-xs, 4px)">
            <Text variant="caption" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
              Humidity
            </Text>
            <Text style={{ fontWeight: 'bold', color: 'var(--ggui-color-on-surface, #000)' }}>
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="column" align="center" gap="var(--ggui-spacing-xs, 4px)">
            <Text variant="caption" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
              Wind Speed
            </Text>
            <Text style={{ fontWeight: 'bold', color: 'var(--ggui-color-on-surface, #000)' }}>
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast */}
        {forecast && forecast.length > 0 && (
          <Stack direction="column" gap="var(--ggui-spacing-sm, 8px)">
            <Text variant="body" style={{ fontWeight: 'bold', color: 'var(--ggui-color-on-surface, #000)' }}>
              5-Day Forecast
            </Text>
            <Stack
              direction="row"
              gap="var(--ggui-spacing-sm, 8px)"
              style={{
                overflowX: 'auto',
                paddingBottom: 'var(--ggui-spacing-xs, 4px)',
              }}
            >
              {forecast.map((day, index) => (
                <ForecastItem key={index} day={day} />
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

