interface ForecastItem {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: object[];
}

const getWeatherEmoji = (condition: string): string => {
  const normalized = condition.trim().toLowerCase();

  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('partly cloudy') || normalized.includes('mostly cloudy')) return '⛅';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) return '❄️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';

  return '🌤️';
};

const formatTemperature = (value: number, unit: string): string => String(value) + '°' + unit;

