            <Box
              padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-primary-50, #f0f9ff)"
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
            >
              <Text color="var(--ggui-color-primary-700, #0369a1)" weight="medium">
                {condition}
              </Text>
            </Box>
          </Row>

          <Row align="center" gap={16} wrap>
