        border: '1px solid var(--ggui-color-border-subtle, #f0f0f0)'
      }}
    >
      <Stack direction="vertical" gap="lg">
        {/* Current Weather Header Section */}
        <Stack direction="vertical" gap="xs">
          <Text 
            variant="h3" 
            style={{ 
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-text-primary, #1a1a1a)'
            }}
          >
            {city}
          </Text>
          <Text 
            variant="body" 
            style={{ color: 'var(--ggui-color-text-secondary, #666)' }}
          >
            Current Weather
          </Text>
        </Stack>

        {/* Temperature & Icon Block */}
        <Stack direction="horizontal" align="center" justify="space-between">
          <Stack direction="vertical" gap="none">
            <Text 
              style={{ 
                fontSize: '4rem', 
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-text-primary, #1a1a1a)',
                lineHeight: 1
              }}
            >
              {Math.round(temperature)}{unit}
            </Text>
            <Text 
              variant="body" 
              style={{ 
                color: 'var(--ggui-color-text-secondary, #666)',
                fontWeight: 'var(--ggui-font-weight-medium, 500)'
              }}
            >
              {condition}
            </Text>
          </Stack>
          <Text 
            style={{ fontSize: '4rem' }} 
            aria-label={"Weather status: " + condition}
            role="img"
          >
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Stats Row Section */}
        <Stack 
          direction="horizontal" 
          justify="space-between" 
          style={{ 
            padding: 'var(--ggui-spacing-md, 16px)',
            backgroundColor: 'var(--ggui-color-surface-variant, #f5f5f5)',
            borderRadius: 'var(--ggui-radius-md, 8px)'
          }}
        >
          <Stack direction="vertical" gap="xs" align="center">
            <Text variant="caption" style={{ color: 'var(--ggui-color-text-secondary, #666)' }}>
              Humidity
            </Text>
            <Text variant="body" style={{ fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="vertical" gap="xs" align="center">
            <Text variant="caption" style={{ color: 'var(--ggui-color-text-secondary, #666)' }}>
              Wind Speed
            </Text>
            <Text variant="body" style={{ fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        {forecast && forecast.length > 0 && (
          <Stack direction="vertical" gap="md">
            <Text 
              variant="caption" 
              style={{ 
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
                color: 'var(--ggui-color-text-tertiary, #888)'
              }}
            >
              5-Day Forecast
            </Text>
            <Stack 
              direction="horizontal" 
              justify="space-between" 
              gap="sm"
              style={{ width: '100%' }}
            >
              {forecast.slice(0, 5).map((day, index) => (
                <Stack 
                  key={day.day + index} 
                  direction="vertical" 
                  align="center" 
                  gap="xs"
                  style={{ flex: 1 }}
                >
                  <Text variant="caption" style={{ fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                    {day.day}
                  </Text>
                  <Text style={{ fontSize: '1.5rem' }} aria-hidden="true" role="presentation">
                    {getWeatherEmoji(day.condition)}
                  </Text>
                  <Stack direction="vertical" gap="none" align="center">
                    <Text variant="caption" style={{ fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                      {day.high}°
                    </Text>
                    <Text variant="caption" style={{ color: 'var(--ggui-color-text-tertiary, #999)', fontSize: '0.7rem' }}>
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider, Box, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = '°C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 16 },
    { day: 'Tue', icon: '🌤️', high: 22, low: 15 },
    { day: 'Wed', icon: '☁️', high: 19, low: 14 },
    { day: 'Thu', icon: '🌧️', high: 17, low: 13 },
    { day: 'Fri', icon: '🌤️', high: 21, low: 15 },
  ],
}: Props) {
  const { motionEnabled } = useMotion();

  // Helper to get condition icon if not provided in forecast or main
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '⛅';
  };

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card 
        padding="var(--ggui-spacing-6, 24px)" 
        shadow="lg"
        style={{
          background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff) 0%, var(--ggui-color-neutral-50, #ffffff) 100%)',
          border: '1px solid var(--ggui-color-primary-100, #e0f2fe)',
          maxWidth: '400px',
          margin: '0 auto',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}
      >
        <Stack gap={24}>
          {/* Header */}
          <Stack gap={4}>
            <Text variant="h3" weight="bold" color="var(--ggui-color-neutral-900)">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-neutral-500)">
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>

          {/* Current Weather */}
          <Row justify="between" align="center">
            <Stack gap={0}>
              <Text 
                style={{ 
                  fontSize: 'var(--ggui-font-size-4xl, 36px)', 
                  lineHeight: '1.2' 
                }} 
                weight="bold" 
                color="var(--ggui-color-neutral-900)"
              >
                {temperature}{unit}
              </Text>
              <Text variant="body" weight="medium" color="var(--ggui-color-primary-600)">
                {condition}
              </Text>
            </Stack>
            <Text style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)' }}>
              {getConditionEmoji(condition)}
            </Text>
          </Row>

          {/* Details */}
          <Row justify="between" style={{ 
            backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
            padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)'
          }}>
            <Stack align="center" gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500)" weight="medium">HUMIDITY</Text>
              <Text variant="body" weight="bold" color="var(--ggui-color-primary-700)">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack align="center" gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500)" weight="medium">WIND</Text>
              <Text variant="body" weight="bold" color="var(--ggui-color-primary-700)">{windSpeed} km/h</Text>
            </Stack>
          </Row>

          <Divider margin={0} />

          {/* Forecast */}
          <Stack gap={16}>
            <Text variant="label" weight="bold" color="var(--ggui-color-neutral-900)">
              5-Day Forecast
            </Text>
            <Row justify="between" align="center" gap={8}>
              {forecast.map((day, index) => (
                <Stack 
                  key={index} 
                  align="center" 
                  gap={4}
                  style={{ 
                    flex: '1 1 0px',
                    minWidth: '50px'
                  }}
                >
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500)">
                    {day.day}
                  </Text>
                  <Text style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}>
                    {day.icon || getConditionEmoji('sunny')}
                  </Text>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-neutral-900)">
                      {day.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-400)">
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Box>
  );
}
